34 | @Command(name = "e2m", description = "Eclipse project to Maven project converter", version = "1.0", mixinStandardHelpOptions = true)
35 | public class Main implements Callable<Integer> {
36 | 
37 |     /** コマンドライン引数のコピー（デバッグ ZIP 用）。 */
38 |     private String[] rawArgs;
39 | 
40 |     @Option(names = {"-g", "--groupId"}, required = false, description = "Maven groupId of the output project")
41 |     private String groupId;
42 | 
43 |     @Option(names = {"-a", "--artifactId"}, required = false, description = "Maven artifactId of the output project")
44 |     private String artifactId;
45 | 
46 |     @Option(names = {"-v", "--artifactVersion"}, required = false, description = "Maven version of the output project (default: 1.0-SNAPSHOT)")
47 |     private String artifactVersion;
48 |     private static final String DEFAULT_ARTIFACT_VERSION = "1.0-SNAPSHOT";
49 | 
50 |     @Option(names = {"--javaTargetVersion"}, required = false, converter = JavaVersionConverter.class,
51 |             description = "Override maven.compiler.target in the generated pom.xml (default: taken from the Eclipse project settings)")
52 |     private JavaVersion javaTargetVersion;
53 | 
54 |     @Option(names = {"--convertToUtf8"}, description = "Convert source files to UTF-8 encoding during copy")
55 |     private boolean convertToUtf8;
56 | 
57 |     @Option(names = {"-e", "--sourceEncoding"}, required = false, description = "Source encoding of the input files (e.g. Shift_JIS). Required when --convertToUtf8 is specified.")
58 |     private String sourceEncoding;
59 | 
60 |     @Option(names = {"--debug"}, description = "Output debug information as e2m_debug_<datetime>.zip in the output directory")
61 |     private boolean debug;
62 | 
63 |     @Parameters(index = "0", paramLabel = "<inputDir>", description = "Eclipse project directory to convert")
64 |     private File inputDir;
65 | 
66 |     @Parameters(index = "1", paramLabel = "<outputDir>", description = "Output directory for the Maven project")
67 |     private File outputDir;
68 | 
69 |     public static void main(String[] args) {
70 |         Main main = new Main();
71 |         main.rawArgs = args.clone();
72 |         System.exit(new CommandLine(main).execute(args));
73 |     }
74 | 
75 |     @Override
76 |     public Integer call() {
77 |         Path inputPath = inputDir.toPath();
78 | 
79 |         // 1. 引数の確認
80 |         if (!inputDir.isDirectory()) {
81 |             System.err.println("[ERROR] 入力ディレクトリが見つかりません: " + inputDir);
82 |             return 1;
83 |         }
84 |         if (!inputPath.resolve(".project").toFile().exists()) {
85 |             System.err.println("[ERROR] Eclipseプロジェクトではありません (.project ファイルが見つかりません): " + inputDir);
86 |             return 1;
87 |         }
88 |         if (outputDir.exists() && !outputDir.isDirectory()) {
89 |             System.err.println("[ERROR] 出力パスはディレクトリである必要があります: " + outputDir);
90 |             return 1;
91 |         }
92 |         if (javaTargetVersion != null && javaTargetVersion.isUnknown()) {
93 |             System.err.println("[ERROR] --javaTargetVersionが不正です: " + javaTargetVersion);
94 |             return 1;
95 |         }
96 | 
97 |         try {
98 |             // 2. Eclipseプロジェクト情報をパース
99 |             System.out.println("\n[1/5] Eclipseプロジェクトを解析中...");
100 |             EclipseProject eclipseProject = EclipseProjectParser.parse(inputPath);
101 |             System.out.println("  プロジェクト名: " + eclipseProject.projectName());
102 |             System.out.println("  種別: " + (eclipseProject.webProject() ? "Webプロジェクト (WTP)" : "Javaプロジェクト"));
103 |             System.out.println("  Javaソースバージョン: " + eclipseProject.javaSourceVersion());
104 |             System.out.println("  Javaターゲットバージョン: " + eclipseProject.javaTargetVersion());
105 |             if (eclipseProject.webProject()) {
106 |                 System.out.println("  Web仕様バージョン: " + eclipseProject.webVersion());
107 |             }
108 |             System.out.println("  ソースフォルダ: " + eclipseProject.sourceFolders());
109 |             if (eclipseProject.webProject()) {
110 |                 System.out.println("  Webコンテンツフォルダ: " + eclipseProject.webContentRoot());
111 |             }
112 |             System.out.println("  JARファイル数: " + eclipseProject.jarPaths().size());
113 | 
114 |             if (eclipseProject.javaSourceVersion().isUnknown()) {
115 |                 System.err.println("[ERROR] Javaソースバージョンを認識できませんでした: "
116 |                         + eclipseProject.javaSourceVersion());
117 |                 return 1;
118 |             }
119 | 
120 |             System.out.println("\n[2/5] 移行先のMavenプロジェクトを決定中...");
121 |             String defaultArtifactId = convertToArtifactId(eclipseProject.projectName());
122 |             if (groupId == null || groupId.isBlank()) {
123 |                 // オプション未指定の場合は対話的に入力を受け付ける
124 |                 try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
125 |                     groupId = promptIfAbsent(reader, "groupId", groupId, null);
126 |                     artifactId = promptIfAbsent(reader, "artifactId", artifactId, defaultArtifactId);
127 |                     artifactVersion = promptIfAbsent(reader, "artifactVersion", artifactVersion, DEFAULT_ARTIFACT_VERSION);
128 |                     // --convert-to-utf8 指定時は sourceEncoding も対話入力
129 |                     if (convertToUtf8) {
130 |                         sourceEncoding = promptIfAbsent(reader, "sourceEncoding", sourceEncoding, null);
131 |                     }
132 |                 }
133 |             } else {
134 |                 // 少なくとも--groupIdが指定されていれば，あとは空ならデフォルトを使用する
135 |                 if (artifactId == null || artifactId.isBlank()) {
136 |                     artifactId = defaultArtifactId;
137 |                 }
138 |                 if (artifactVersion == null || artifactId.isBlank()) {
139 |                     artifactVersion = DEFAULT_ARTIFACT_VERSION;
140 |                 }
141 |                 System.out.println("groupId: " + groupId);
142 |                 System.out.println("artifactId: " + artifactId);
143 |                 System.out.println("version: " + artifactVersion);
144 |                 // --convert-to-utf8 指定時は sourceEncoding も対話入力（--groupId 指定時で未指定の場合）
145 |                 if (convertToUtf8 && (sourceEncoding == null || sourceEncoding.isBlank())) {
146 |                     try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
147 |                         sourceEncoding = promptIfAbsent(reader, "sourceEncoding", sourceEncoding, null);
148 |                     }
149 |                 }
150 |             }
151 | 
152 |             // --convert-to-utf8 指定時の sourceEncoding バリデーション
153 |             Charset srcCharset = null;
154 |             if (convertToUtf8) {
155 |                 try {
156 |                     srcCharset = Charset.forName(sourceEncoding);
157 |                 } catch (Exception e) {
158 |                     System.err.println("[ERROR] --sourceEncoding が無効な文字セット名です: " + sourceEncoding);
159 |                     return 1;
160 |                 }
161 |             }
162 | 
163 |             // 出力先は outputDir/artifactId
164 |             Path outputPath = outputDir.toPath().resolve(artifactId);
165 |             if (outputPath.toFile().exists()) {
166 |                 System.err.println("[ERROR] 出力先ディレクトリがすでに存在しています: " + outputPath);
167 |                 return 1;
168 |             }
169 | 
170 |             System.out.println("\n=== e2m: Eclipse → Maven 変換開始 ===");
171 |             System.out.println("  入力: " + inputPath.toAbsolutePath());
172 |             System.out.println("  出力: " + outputPath.toAbsolutePath());
173 | 
174 |             // 3.(続き) JAR依存関係を解決
175 |             System.out.println("\n[3/5] JAR依存関係を解決中...");
176 |             List<MavenDependency> dependencies = DependencyResolver.resolve(eclipseProject.jarPaths(), inputPath);
177 |             long found = dependencies.stream().filter(d -> !"system".equals(d.scope())).count();
178 |             long system = dependencies.stream().filter(d -> "system".equals(d.scope())).count();
179 |             System.out.println("  Maven Central で見つかった依存: " + found + " 件");
180 |             System.out.println("  system スコープの依存: " + system + " 件");
181 | 
182 |             // 4. pom.xml を生成
183 |             System.out.println("\n[4/5] pom.xml を生成中...");
184 |             // --javaTargetVersion が指定された場合はソースバージョンと比較してバリデーション
185 |             JavaVersion sourceVer = eclipseProject.javaSourceVersion();
186 |             if (javaTargetVersion != null) {
187 |                 if (!sourceVer.isUnknown() && javaTargetVersion.compareTo(sourceVer) < 0) {
188 |                     System.err.println("[ERROR] --javaTargetVersion (" + javaTargetVersion
189 |                             + ") はJavaソースバージョン (" + eclipseProject.javaSourceVersion()
190 |                             + ") より低いバージョンを指定することはできません。");
191 |                     return 1;
192 |                 }
193 |             }
194 |             // 実効 javaTargetVersion を確定（--javaTargetVersion 指定 > Eclipseプロジェクト設定）
195 |             JavaVersion effectiveTargetVersion = (javaTargetVersion != null && !javaTargetVersion.isUnknown())
196 |                     ? javaTargetVersion
197 |                     : eclipseProject.javaTargetVersion();
198 |             PomGenerator.generate(eclipseProject, dependencies, groupId, artifactId, artifactVersion,
199 |                     effectiveTargetVersion, convertToUtf8, outputPath);
200 | 
201 |             // 5. ソース・Webコンテンツをコピー
202 |             System.out.println("\n[5/5] ソースファイルをコピー中...");
203 |             if (convertToUtf8) {
204 |                 System.out.println("  エンコーディング変換モード: " + sourceEncoding + " → UTF-8");
205 |             }
206 |             ProjectCopier.copy(eclipseProject, dependencies, inputPath, outputPath,
207 |                     convertToUtf8, srcCharset, effectiveTargetVersion);
208 | 
209 |             System.out.println("\n=== 変換完了 ===");
210 |             System.out.println("出力先: " + outputPath.toAbsolutePath());
211 | 
212 |             // --debug オプション: デバッグ ZIP を生成
213 |             if (debug) {
214 |                 DebugArchiver.archive(inputPath, outputDir.toPath(), outputPath, rawArgs);
215 |             }
216 | 
217 |             return 0;
218 | 
219 |         } catch (Exception e) {
220 |             System.err.println("[ERROR] 変換中にエラーが発生しました: " + e.getMessage());
221 |             e.printStackTrace(System.err);
222 |             return 2;
223 |         }
224 |     }
