226 |     /**
227 |      * 引数が null または空の場合にプロンプトを表示して入力を受け付ける。
228 |      * デフォルト値がある場合は "[default]" 形式で表示し、空入力でデフォルト値を採用する。
229 |      *
230 |      * @param reader       入力ストリーム
231 |      * @param name         項目名（表示用）
232 |      * @param value        コマンドライン引数の値（null または空の場合にプロンプト表示）
233 |      * @param defaultValue デフォルト値（null の場合はデフォルトなし）
234 |      * @return 確定した値
235 |      */
236 |     private static String promptIfAbsent(BufferedReader reader, String name,
237 |             String value, String defaultValue) throws Exception {
238 |         if (value != null && !value.isBlank()) {
239 |             return value;
240 |         }
241 |         while (true) {
242 |             if (defaultValue != null) {
243 |                 System.out.print(name + " [" + defaultValue + "]: ");
244 |             } else {
245 |                 System.out.print(name + ": ");
246 |             }
247 |             System.out.flush();
248 |             String line = reader.readLine();
249 |             if (line == null) {
250 |                 // EOF（パイプ等）の場合はデフォルト値を使用
251 |                 return defaultValue != null ? defaultValue : "";
252 |             }
253 |             String trimmed = line.trim();
254 |             if (trimmed.isEmpty()) {
255 |                 if (defaultValue != null) {
256 |                     return defaultValue;
257 |                 }
258 |                 System.err.println("  値を入力してください。");
259 |                 continue;
260 |             }
261 |             return trimmed;
262 |         }
263 |     }
