265 |     // artifactIdとして許可する文字（半角英数字、ハイフン、アンダースコア）以外にマッチする正規表現
266 |     private static final Pattern INVALID_CHARS = Pattern.compile("[^a-z0-9\\-_]");
267 | 
268 |     // キャメルケースの境界（大文字の前）にマッチする正規表現
269 |     private static final Pattern CAMEL_CASE_BOUNDARY = Pattern.compile("(?<=[a-z0-9])(?=[A-Z])");
270 | 
271 |     /**
272 |      * プロジェクト名からMavenのartifactIdとして利用可能な文字列を生成します。
273 |      *
274 |      * @param projectName プロジェクト名
275 |      * @return artifactId用文字列
276 |      */
277 |     public static String convertToArtifactId(String projectName) {
278 |         if (projectName == null || projectName.isBlank()) {
279 |             return "default-artifact";
280 |         }
281 | 
282 |         // 1. パッケージ名が含まれている場合（完全限定名）、最後のクラス名部分だけを抽出
283 |         String simpleName = projectName.substring(projectName.lastIndexOf('.') + 1);
284 | 
285 |         // 2. キャメルケース（OrderManager -> Order-Manager）をハイフン区切りに変換
286 |         String kebabCase = CAMEL_CASE_BOUNDARY.matcher(simpleName).replaceAll("-");
287 | 
288 |         // 3. すべて小文字に変換
289 |         String lowerCase = kebabCase.toLowerCase();
290 | 
291 |         // 4. artifactIdとして使えない文字（日本語や特殊記号など）を完全に除去
292 |         String sanitized = INVALID_CHARS.matcher(lowerCase).replaceAll("");
293 | 
294 |         // 5. 連続したハイフンやアンダースコアを綺麗に整理
295 |         sanitized = sanitized.replaceAll("[-_]{2,}", "-");
296 | 
297 |         // 6. 先頭や末尾にあるハイフン・アンダースコアを除去
298 |         sanitized = sanitized.replaceAll("^[-_]+|[-_]+$", "");
299 | 
300 |         // すべての文字が削られて空になった場合のフォールバック
301 |         return sanitized.isBlank() ? "converted-artifact" : sanitized;
302 |     }
