29 | /**
30 |  * EclipseプロジェクトのソースファイルをMavenの標準ディレクトリ構造にコピーするクラス。
31 |  *
32 |  * <ul>
33 |  *   <li>Javaソース (.java) → src/main/java/ または src/test/java/</li>
34 |  *   <li>リソースファイル (非.java) → src/main/resources/ または src/test/resources/</li>
35 |  *   <li>Webコンテンツ (WTPプロジェクトの場合) → src/main/webapp/</li>
36 |  * </ul>
37 |  *
38 |  * <p>{@code convertToUtf8} が {@code true} の場合、以下の変換を行う：</p>
39 |  * <ul>
40 |  *   <li>{@code .java} ファイル: {@code sourceEncoding} で読み込み、UTF-8 で書き出す</li>
41 |  *   <li>{@code .properties} ファイル: {@code sourceEncoding} で読み込み、Unicode エスケープを
42 |  *       Unicode 文字に展開して UTF-8 で書き出す。{@code effectiveTargetVersion <= 8} の場合は
43 |  *       {@code src/main/resources-utf8/} へ出力する</li>
44 |  *   <li>{@code .jsp} ファイル: {@code pageEncoding} 属性を検出してそのエンコードで読み込み、
45 |  *       属性値を {@code UTF-8} に書き換えて出力する</li>
46 |  * </ul>
47 |  */
48 | public class ProjectCopier {
49 | 
50 |     private ProjectCopier() {}
51 | 
52 |     /** ISO-8859-1 でプリアンブルを読む際のバッファサイズ（4KB）。 */
53 |     private static final int JSP_PREAMBLE_BYTES = 4096;
54 | 
55 |     /** JSP の pageEncoding 属性を検出する正規表現。 */
56 |     private static final Pattern JSP_PAGE_ENCODING_PATTERN =
57 |             Pattern.compile("<%@\\s*page\\b[^%]*\\bpageEncoding\\s*=\\s*[\"']([^\"']+)[\"']",
58 |                     Pattern.DOTALL);
59 | 
60 |     /** properties ファイルの Unicode エスケープシーケンスを検出する正規表現。 */
61 |     private static final Pattern UNICODE_ESCAPE_PATTERN =
62 |             Pattern.compile("\\\\u([0-9a-fA-F]{4})");
63 | 
64 |     /**
65 |      * EclipseプロジェクトのファイルをMaven標準ディレクトリ構造にコピーする。
66 |      *
67 |      * @param eclipseProject        パース済みEclipseプロジェクト情報
68 |      * @param dependencies          解決済み依存関係リスト（system スコープの JAR を libs/ にコピーする）
69 |      * @param inputDir              Eclipseプロジェクトのルートディレクトリ
70 |      * @param outputDir             Mavenプロジェクトの出力ルートディレクトリ
71 |      * @param convertToUtf8         true の場合はエンコーディング変換を行う
72 |      * @param sourceEncoding        変換元エンコーディング（convertToUtf8=false の場合は無視）
73 |      * @param effectiveTargetVersion 実効Javaターゲットバージョン（.properties 出力先の判定に使用）
74 |      * @throws IOException ファイルコピーに失敗した場合
75 |      */
76 |     public static void copy(EclipseProject eclipseProject, List<MavenDependency> dependencies,
77 |                             Path inputDir, Path outputDir,
78 |                             boolean convertToUtf8, Charset sourceEncoding,
79 |                             JavaVersion effectiveTargetVersion) throws IOException {
80 | 
81 |         // Javaソースフォルダのコピー
82 |         List<String> sourceFolders = eclipseProject.sourceFolders();
83 |         for (String sourceFolder : sourceFolders) {
84 |             Path srcPath = resolveSourcePath(inputDir, sourceFolder);
85 |             if (!Files.isDirectory(srcPath)) {
86 |                 System.out.println("  [WARN] ソースフォルダが見つかりません: " + srcPath);
87 |                 continue;
88 |             }
89 |             boolean isTest = isTestFolder(sourceFolder);
90 |             Path javaDestBase = outputDir.resolve(isTest ? "src/test/java" : "src/main/java");
91 |             // .properties の出力先: Java 9+ → src/main/resources/、Java 8以下 → src/main/resources-utf8/
92 |             boolean useUtf8ResourceDir = convertToUtf8 && !effectiveTargetVersion.isUnknown()
93 |                     && effectiveTargetVersion.compareTo(JavaVersion.Java8) <= 0;
94 |             Path resourceDestBase = outputDir.resolve(
95 |                     isTest ? "src/test/resources"
96 |                            : (useUtf8ResourceDir ? "src/main/resources-utf8" : "src/main/resources"));
97 |             Path resourceDestNormal = outputDir.resolve(isTest ? "src/test/resources" : "src/main/resources");
98 | 
99 |             copySourceFolder(srcPath, srcPath, javaDestBase, resourceDestBase, resourceDestNormal,
100 |                     convertToUtf8, sourceEncoding);
101 |         }
102 | 
103 |         // Webコンテンツのコピー（WTPプロジェクトの場合）
104 |         if (eclipseProject.webProject() && eclipseProject.webContentRoot() != null) {
105 |             Path webContentPath = resolveSourcePath(inputDir, eclipseProject.webContentRoot());
106 |             if (Files.isDirectory(webContentPath)) {
107 |                 Path webappDest = outputDir.resolve("src/main/webapp");
108 |                 copyWebContents(webContentPath, webappDest, convertToUtf8, sourceEncoding);
109 |                 System.out.println("  Copied web content: " + webContentPath + " → " + webappDest);
110 |             } else {
111 |                 System.out.println("  [WARN] Webコンテンツルートが見つかりません: " + webContentPath);
112 |             }
113 |         }
114 | 
115 |         // system スコープの JAR を libs/ にコピー
116 |         for (MavenDependency dep : dependencies) {
117 |             if ("system".equals(dep.scope()) && dep.systemPath() != null) {
118 |                 Path src = Path.of(dep.systemPath());
119 |                 if (Files.isRegularFile(src)) {
120 |                     Path libsDir = outputDir.resolve("libs");
121 |                     Files.createDirectories(libsDir);
122 |                     Path dest = libsDir.resolve(src.getFileName());
123 |                     Files.copy(src, dest, StandardCopyOption.REPLACE_EXISTING);
124 |                     System.out.println("  Copied JAR to libs/: " + dest.getFileName());
125 |                 }
126 |             }
127 |         }
128 |     }
