130 |     /**
131 |      * ソースフォルダ内のファイルを.javaとリソースに振り分けてコピーする。
132 |      *
133 |      * @param baseDir            コピー元のルート（相対パス計算の基点）
134 |      * @param currentDir         現在処理中のディレクトリ
135 |      * @param javaDestBase       .javaファイルのコピー先ベースディレクトリ
136 |      * @param resourceDest       リソースファイルのコピー先ベースディレクトリ（.properties はここへ）
137 |      * @param resourceDestNormal 通常のリソースコピー先（.properties 以外の非.javaファイルはここへ）
138 |      * @param convertToUtf8      true の場合はエンコーディング変換を行う
139 |      * @param sourceEncoding     変換元エンコーディング
140 |      * @throws IOException ファイルコピーに失敗した場合
141 |      */
142 |     private static void copySourceFolder(Path baseDir, Path currentDir, Path javaDestBase,
143 |                                          Path resourceDest, Path resourceDestNormal,
144 |                                          boolean convertToUtf8, Charset sourceEncoding)
145 |             throws IOException {
146 |         Files.walk(currentDir)
147 |                 .filter(Files::isRegularFile)
148 |                 .forEach(srcFile -> {
149 |                     try {
150 |                         Path relative = baseDir.relativize(srcFile);
151 |                         String fileName = srcFile.getFileName().toString();
152 |                         boolean isJava = fileName.endsWith(".java");
153 |                         boolean isProperties = fileName.endsWith(".properties");
154 | 
155 |                         if (isJava) {
156 |                             Path destFile = javaDestBase.resolve(relative);
157 |                             Files.createDirectories(destFile.getParent());
158 |                             if (convertToUtf8) {
159 |                                 copyWithEncodingConversion(srcFile, destFile, sourceEncoding);
160 |                                 System.out.println("  [UTF-8変換] " + relative);
161 |                             } else {
162 |                                 Files.copy(srcFile, destFile, StandardCopyOption.REPLACE_EXISTING);
163 |                             }
164 |                         } else if (isProperties && convertToUtf8) {
165 |                             // .properties: Unicode エスケープ展開 + UTF-8 で resourceDest へ
166 |                             Path destFile = resourceDest.resolve(relative);
167 |                             Files.createDirectories(destFile.getParent());
168 |                             copyPropertiesWithConversion(srcFile, destFile, sourceEncoding);
169 |                             System.out.println("  [UTF-8変換] " + relative);
170 |                         } else {
171 |                             // その他のリソース（バイナリコピー）
172 |                             Path destFile = resourceDestNormal.resolve(relative);
173 |                             Files.createDirectories(destFile.getParent());
174 |                             Files.copy(srcFile, destFile, StandardCopyOption.REPLACE_EXISTING);
175 |                         }
176 |                     } catch (IOException e) {
177 |                         throw new RuntimeException("ファイルコピーに失敗しました: " + srcFile, e);
178 |                     }
179 |                 });
180 |         System.out.println("  Copied source folder: " + currentDir + " → " + javaDestBase);
181 |     }
182 | 
183 |     /**
184 |      * Webコンテンツディレクトリを再帰的にコピーする。
185 |      * WEB-INF/lib 直下の .jar ファイルはスキップする。
186 |      * {@code convertToUtf8=true} の場合、.jsp ファイルはエンコーディング変換を行う。
187 |      *
188 |      * @param srcDir         コピー元ディレクトリ
189 |      * @param destDir        コピー先ディレクトリ
190 |      * @param convertToUtf8  true の場合はエンコーディング変換を行う
191 |      * @param sourceEncoding 変換元エンコーディング（.jsp の pageEncoding が不明な場合に使用）
192 |      * @throws IOException ファイルコピーに失敗した場合
193 |      */
194 |     private static void copyWebContents(Path srcDir, Path destDir,
195 |                                         boolean convertToUtf8, Charset sourceEncoding)
196 |             throws IOException {
197 |         Path excludeJarDir = srcDir.resolve("WEB-INF/lib");
198 |         Files.walk(srcDir)
199 |                 .filter(srcPath -> !srcPath.startsWith(excludeJarDir)
200 |                         || !srcPath.getFileName().toString().endsWith(".jar"))
201 |                 .forEach(srcPath -> {
202 |                     try {
203 |                         Path relative = srcDir.relativize(srcPath);
204 |                         Path destPath = destDir.resolve(relative);
205 |                         if (Files.isDirectory(srcPath)) {
206 |                             Files.createDirectories(destPath);
207 |                         } else {
208 |                             Files.createDirectories(destPath.getParent());
209 |                             String fileName = srcPath.getFileName().toString();
210 |                             if (convertToUtf8 && fileName.endsWith(".jsp")) {
211 |                                 Charset jspEncoding = extractJspPageEncoding(srcPath, sourceEncoding);
212 |                                 if (jspEncoding != null) {
213 |                                     copyJspWithConversion(srcPath, destPath, jspEncoding);
214 |                                     System.out.println("  [UTF-8変換] " + relative);
215 |                                 } else {
216 |                                     // pageEncoding が既に UTF-8 → バイナリコピー
217 |                                     Files.copy(srcPath, destPath, StandardCopyOption.REPLACE_EXISTING);
218 |                                 }
219 |                             } else {
220 |                                 Files.copy(srcPath, destPath, StandardCopyOption.REPLACE_EXISTING);
221 |                             }
222 |                         }
223 |                     } catch (IOException e) {
224 |                         throw new RuntimeException("ファイルコピーに失敗しました: " + srcPath, e);
225 |                     }
226 |                 });
227 |     }
