229 |     /**
230 |      * テキストファイルを指定エンコードで読み込み、UTF-8 で書き出す。
231 |      *
232 |      * @param src  コピー元ファイル
233 |      * @param dest コピー先ファイル
234 |      * @param from 変換元エンコーディング
235 |      * @throws IOException ファイル読み書きに失敗した場合
236 |      */
237 |     static void copyWithEncodingConversion(Path src, Path dest, Charset from) throws IOException {
238 |         String content = Files.readString(src, from);
239 |         Files.writeString(dest, content, StandardCharsets.UTF_8);
240 |     }
241 | 
242 |     /**
243 |      * .properties ファイルを指定エンコードで読み込み、Unicode エスケープを展開して UTF-8 で書き出す。
244 |      *
245 |      * @param src  コピー元ファイル
246 |      * @param dest コピー先ファイル
247 |      * @param from 変換元エンコーディング
248 |      * @throws IOException ファイル読み書きに失敗した場合
249 |      */
250 |     static void copyPropertiesWithConversion(Path src, Path dest, Charset from) throws IOException {
251 |         List<String> lines = Files.readAllLines(src, from);
252 |         List<String> converted = lines.stream()
253 |                 .map(ProjectCopier::unescapeUnicode)
254 |                 .toList();
255 |         Files.write(dest, converted, StandardCharsets.UTF_8);
256 |     }
257 | 
258 |     /**
259 |      * 文字列中の Unicode エスケープシーケンス（&#92;uXXXX 形式）を Unicode 文字に展開する。
260 |      *
261 |      * @param line 入力文字列
262 |      * @return Unicode エスケープを展開した文字列
263 |      */
264 |     static String unescapeUnicode(String line) {
265 |         Matcher m = UNICODE_ESCAPE_PATTERN.matcher(line);
266 |         if (!m.find()) {
267 |             return line;
268 |         }
269 |         m.reset();
270 |         StringBuilder sb = new StringBuilder();
271 |         while (m.find()) {
272 |             int codePoint = Integer.parseInt(m.group(1), 16);
273 |             m.appendReplacement(sb, Matcher.quoteReplacement(String.valueOf((char) codePoint)));
274 |         }
275 |         m.appendTail(sb);
276 |         return sb.toString();
277 |     }
278 | 
279 |     /**
280 |      * JSP ファイルの先頭 4KB を ISO-8859-1 で読み込み、{@code pageEncoding} 属性を検出する。
281 |      *
282 |      * <ul>
283 |      *   <li>検出でき、かつ UTF-8 系でない場合: そのエンコーディングの {@link Charset} を返す</li>
284 |      *   <li>検出できない場合: {@code fallback} を返す</li>
285 |      *   <li>検出でき、かつ既に UTF-8 系の場合: {@code null} を返す（呼び出し元でバイナリコピーに切り替える）</li>
286 |      * </ul>
287 |      *
288 |      * @param jspFile  JSP ファイルのパス
289 |      * @param fallback pageEncoding が見つからない場合に返すエンコーディング
290 |      * @return 変換元エンコーディング、または null（既に UTF-8 の場合）
291 |      * @throws IOException ファイル読み込みに失敗した場合
292 |      */
293 |     static Charset extractJspPageEncoding(Path jspFile, Charset fallback) throws IOException {
294 |         // 先頭 4KB を ISO-8859-1 で読み込む（バイト値をそのまま文字として扱うため）
295 |         byte[] bytes = Files.readAllBytes(jspFile);
296 |         int len = Math.min(bytes.length, JSP_PREAMBLE_BYTES);
297 |         String preamble = new String(bytes, 0, len, StandardCharsets.ISO_8859_1);
298 | 
299 |         Matcher m = JSP_PAGE_ENCODING_PATTERN.matcher(preamble);
300 |         if (!m.find()) {
301 |             return fallback;
302 |         }
303 |         String encodingName = m.group(1).trim();
304 |         // 既に UTF-8 系であれば null を返す
305 |         if (encodingName.equalsIgnoreCase("UTF-8") || encodingName.equalsIgnoreCase("UTF8")) {
306 |             return null;
307 |         }
308 |         try {
309 |             return Charset.forName(encodingName);
310 |         } catch (Exception e) {
311 |             // 不明なエンコーディング名の場合は fallback を使用
312 |             System.out.println("  [WARN] JSP の pageEncoding が不明です: " + encodingName + " → fallback を使用");
313 |             return fallback;
314 |         }
315 |     }
316 | 
317 |     /**
318 |      * JSP ファイルを指定エンコードで読み込み、{@code pageEncoding} 属性値を {@code UTF-8} に書き換えて出力する。
319 |      *
320 |      * @param src  コピー元 JSP ファイル
321 |      * @param dest コピー先ファイル
322 |      * @param from 変換元エンコーディング
323 |      * @throws IOException ファイル読み書きに失敗した場合
324 |      */
325 |     static void copyJspWithConversion(Path src, Path dest, Charset from) throws IOException {
326 |         String content = Files.readString(src, from);
327 |         // pageEncoding 属性値を UTF-8 に書き換える（シングルクォートとダブルクォートの両方に対応）
328 |         String converted = content.replaceAll(
329 |                 "(<%@\\s*page\\b[^%]*\\bpageEncoding\\s*=\\s*)([\"'])([^\"']+)\\2",
330 |                 "$1$2UTF-8$2");
331 |         Files.writeString(dest, converted, StandardCharsets.UTF_8);
332 |     }
333 | 
334 |     /**
335 |      * ソースフォルダのパス文字列をinputDir基点の絶対Pathに解決する。
336 |      * 先頭の '/' は除去して相対パスとして扱う。
337 |      */
338 |     private static Path resolveSourcePath(Path inputDir, String folderPath) {
339 |         String normalized = folderPath.startsWith("/") ? folderPath.substring(1) : folderPath;
340 |         if (normalized.isEmpty()) {
341 |             return inputDir;
342 |         }
343 |         return inputDir.resolve(normalized);
344 |     }
345 | 
346 |     /**
347 |      * ソースフォルダ名に "test" が含まれるかどうかを判定する。
348 |      * パスの各セグメントを小文字で比較する。
349 |      */
350 |     static boolean isTestFolder(String folderPath) {
351 |         String lower = folderPath.toLowerCase();
352 |         for (String segment : lower.split("[/\\\\]")) {
353 |             if (segment.equals("test") || segment.startsWith("test-") || segment.endsWith("-test")
354 |                     || segment.contains("test")) {
355 |                 return true;
356 |             }
357 |         }
358 |         return false;
359 |     }
360 | }
