33 | /**
34 |  * EclipseProject情報と依存関係リストからMavenのpom.xmlを生成するクラス。
35 |  */
36 | public class PomGenerator {
37 | 
38 |     private static final String MAVEN_COMPILER_PLUGIN_VERSION = "3.15.0";
39 |     private static final String MAVEN_WAR_PLUGIN_VERSION = "3.5.1";
40 |     private static final String NATIVE2ASCII_PLUGIN_VERSION = "2.1.1";
41 | 
42 |     private PomGenerator() {}
43 | 
44 |     /**
45 |      * pom.xmlを生成して出力ディレクトリに保存する。
46 |      *
47 |      * @param eclipseProject        パース済みEclipseプロジェクト情報
48 |      * @param dependencies          解決済み依存関係リスト
49 |      * @param groupId               生成するpom.xmlのgroupId
50 |      * @param artifactId            生成するpom.xmlのartifactId
51 |      * @param version               生成するpom.xmlのversion
52 |      * @param effectiveTargetVersion maven.compiler.targetに使用するJavaバージョン。
53 |      * @param convertToUtf8      --convert-to-utf8 オプションが指定されているか
54 |      * @param outputDir          出力ディレクトリ
55 |      * @throws Exception XML生成またはファイル書き込みに失敗した場合
56 |      */
57 |     public static void generate(
58 |             EclipseProject eclipseProject,
59 |             List<MavenDependency> dependencies,
60 |             String groupId,
61 |             String artifactId,
62 |             String version,
63 |             JavaVersion effectiveTargetVersion,
64 |             boolean convertToUtf8,
65 |             Path outputDir) throws Exception {
66 | 
67 |         DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
68 |         DocumentBuilder db = dbf.newDocumentBuilder();
69 |         Document doc = db.newDocument();
70 | 
71 |         // <project>
72 |         Element project = doc.createElement("project");
73 |         project.setAttribute("xmlns", "http://maven.apache.org/POM/4.0.0");
74 |         project.setAttribute("xmlns:xsi", "http://www.w3.org/2001/XMLSchema-instance");
75 |         project.setAttribute("xsi:schemaLocation",
76 |                 "http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd");
77 |         doc.appendChild(project);
78 | 
79 |         addTextElement(doc, project, "modelVersion", "4.0.0");
80 |         addTextElement(doc, project, "groupId", groupId);
81 |         addTextElement(doc, project, "artifactId", artifactId);
82 |         addTextElement(doc, project, "version", version);
83 | 
84 |         if (eclipseProject.webProject()) {
85 |             addTextElement(doc, project, "packaging", "war");
86 |         }
87 | 
88 |         // <properties>
89 |         JavaVersion javaSourceVersion = eclipseProject.javaSourceVersion();
90 |         JavaVersion javaTargetVersion = effectiveTargetVersion;
91 |         Element properties = doc.createElement("properties");
92 |         addTextElement(doc, properties, "project.build.sourceEncoding", "UTF-8");
93 |         addTextElement(doc, properties, "maven.compiler.source", javaSourceVersion.toString());
94 |         addTextElement(doc, properties, "maven.compiler.target", javaTargetVersion.toString());
95 |         project.appendChild(properties);
96 | 
97 |         // <dependencies>
98 |         boolean hasDependencies = !dependencies.isEmpty() || eclipseProject.webProject();
99 |         if (hasDependencies) {
100 |             Element deps = doc.createElement("dependencies");
101 |             for (MavenDependency dep : dependencies) {
102 |                 Element dependency = doc.createElement("dependency");
103 |                 addTextElement(doc, dependency, "groupId", dep.groupId());
104 |                 addTextElement(doc, dependency, "artifactId", dep.artifactId());
105 |                 addTextElement(doc, dependency, "version", dep.version());
106 |                 if (dep.scope() != null && !dep.scope().isEmpty()) {
107 |                     addTextElement(doc, dependency, "scope", dep.scope());
108 |                 }
109 |                 if (dep.systemPath() != null) {
110 |                     // system スコープの JAR は libs/ にコピーされるため ${project.basedir}/libs/<ファイル名> で参照
111 |                     String fileName = Path.of(dep.systemPath()).getFileName().toString();
112 |                     addTextElement(doc, dependency, "systemPath",
113 |                             "${project.basedir}/libs/" + fileName);
114 |                 }
115 |                 deps.appendChild(dependency);
116 |             }
117 |             // webProject の場合は Java EE / Jakarta EE API を provided で追加
118 |             if (eclipseProject.webProject() && eclipseProject.webVersion() != null) {
119 |                 String webVersion = eclipseProject.webVersion();
120 |                 boolean tooOld = webVersion.startsWith("2");
121 |                 String resolvedVersion = tooOld ? "3.0" : webVersion;
122 |                 JavaEEVersion javaEE = JavaEEVersion.of(resolvedVersion);
123 |                 Element dependency = doc.createElement("dependency");
124 |                 if (tooOld) {
125 |                     deps.appendChild(doc.createComment(
126 |                             " WARNING: Servlet " + webVersion + " は古すぎるため対応する javaee-api dependency が存在しません。"
127 |                             + " Java EE 6 (javaee-api:6.0) に置き換えています。マイグレーションが必要です。 "));
128 |                 }
129 |                 addTextElement(doc, dependency, "groupId", javaEE.getGroupId());
130 |                 addTextElement(doc, dependency, "artifactId", javaEE.getArtifactId());
131 |                 addTextElement(doc, dependency, "version", javaEE.getVersion());
132 |                 addTextElement(doc, dependency, "scope", "provided");
133 |                 deps.appendChild(dependency);
134 |             }
135 |             project.appendChild(deps);
136 |         }
137 | 
138 |         // <build><plugins><plugin> maven-compiler-plugin
139 |         Element build = doc.createElement("build");
140 |         Element plugins = doc.createElement("plugins");
141 |         Element plugin = doc.createElement("plugin");
142 |         addTextElement(doc, plugin, "groupId", "org.apache.maven.plugins");
143 |         addTextElement(doc, plugin, "artifactId", "maven-compiler-plugin");
144 |         addTextElement(doc, plugin, "version", MAVEN_COMPILER_PLUGIN_VERSION);
145 |         plugins.appendChild(plugin);
146 |         // webProject の場合は maven-war-plugin を追加
147 |         if (eclipseProject.webProject()) {
148 |             Element warPlugin = doc.createElement("plugin");
149 |             addTextElement(doc, warPlugin, "groupId", "org.apache.maven.plugins");
150 |             addTextElement(doc, warPlugin, "artifactId", "maven-war-plugin");
151 |             addTextElement(doc, warPlugin, "version", MAVEN_WAR_PLUGIN_VERSION);
152 |             Element configuration = doc.createElement("configuration");
153 |             addTextElement(doc, configuration, "failOnMissingWebXml", "false");
154 |             warPlugin.appendChild(configuration);
155 |             plugins.appendChild(warPlugin);
156 |         }
157 |         // --convert-to-utf8 かつ javaTargetVersion <= 8 の場合は native2ascii-maven-plugin を追加
158 |         // javaTargetVersion は 93-96 行で確定済み（javaTargetOverride 優先）
159 |         if (convertToUtf8 && !javaTargetVersion.isUnknown()
160 |                 && javaTargetVersion.compareTo(JavaVersion.Java8) <= 0) {
161 |             Element n2aPlugin = doc.createElement("plugin");
162 |             addTextElement(doc, n2aPlugin, "groupId", "org.codehaus.mojo");
163 |             addTextElement(doc, n2aPlugin, "artifactId", "native2ascii-maven-plugin");
164 |             addTextElement(doc, n2aPlugin, "version", NATIVE2ASCII_PLUGIN_VERSION);
165 |             Element executions = doc.createElement("executions");
166 |             Element execution = doc.createElement("execution");
167 |             addTextElement(doc, execution, "id", "native2ascii-utf8-resources");
168 |             addTextElement(doc, execution, "phase", "process-resources");
169 |             Element goals = doc.createElement("goals");
170 |             addTextElement(doc, goals, "goal", "resources");
171 |             execution.appendChild(goals);
172 |             Element configuration = doc.createElement("configuration");
173 |             addTextElement(doc, configuration, "encoding", "UTF-8");
174 |             addTextElement(doc, configuration, "srcDir", "${project.basedir}/src/main/resources-utf8");
175 |             addTextElement(doc, configuration, "outputDir", "${project.build.outputDirectory}");
176 |             execution.appendChild(configuration);
177 |             executions.appendChild(execution);
178 |             n2aPlugin.appendChild(executions);
179 |             plugins.appendChild(n2aPlugin);
180 |         }
181 |         build.appendChild(plugins);
182 |         project.appendChild(build);
183 | 
184 |         // XMLをファイルに書き出す
185 |         Files.createDirectories(outputDir);
186 |         TransformerFactory tf = TransformerFactory.newInstance();
187 |         Transformer transformer = tf.newTransformer();
188 |         transformer.setOutputProperty(OutputKeys.INDENT, "yes");
189 |         transformer.setOutputProperty(OutputKeys.ENCODING, "UTF-8");
190 |         transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");
191 | 
192 |         Path pomPath = outputDir.resolve("pom.xml");
193 |         transformer.transform(new DOMSource(doc), new StreamResult(pomPath.toFile()));
194 | 
195 |         System.out.println("Generated: " + pomPath);
196 |     }
197 | 
198 |     private static void addTextElement(Document doc, Element parent, String tagName, String text) {
199 |         Element el = doc.createElement(tagName);
200 |         el.appendChild(doc.createTextNode(text));
201 |         parent.appendChild(el);
202 |     }
203 | }
