32 | /**
33 |  * Eclipseプロジェクトのメタデータファイルを解析して {@link EclipseProject} を返すパーサー。
34 |  */
35 | public class EclipseProjectParser {
36 | 
37 |     private static final String WTP_NATURE = "org.eclipse.wst.common.project.facet.core.nature";
38 |     private static final String DEFAULT_JAVA_VERSION = "11";
39 | 
40 |     /**
41 |      * 指定した入力ディレクトリを解析して {@link EclipseProject} を返す。
42 |      *
43 |      * @param inputDir Eclipseプロジェクトのルートディレクトリ
44 |      * @return 解析結果
45 |      * @throws Exception 解析中に発生した例外
46 |      */
47 |     public static EclipseProject parse(Path inputDir) throws Exception {
48 |         DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
49 |         DocumentBuilder builder = factory.newDocumentBuilder();
50 | 
51 |         // ── .project ──────────────────────────────────────────────
52 |         Path projectFile = inputDir.resolve(".project");
53 |         // 行頭の空白・改行をスキップするため InputStream 経由でパース
54 |         Document projectDoc = builder.parse(
55 |                 new java.io.ByteArrayInputStream(
56 |                         Files.readString(projectFile).stripLeading().getBytes(java.nio.charset.StandardCharsets.UTF_8)));
57 |         projectDoc.getDocumentElement().normalize();
58 | 
59 |         String projectName = projectDoc.getElementsByTagName("name")
60 |                 .item(0).getTextContent().trim();
61 | 
62 |         boolean webProject = false;
63 |         NodeList natures = projectDoc.getElementsByTagName("nature");
64 |         for (int i = 0; i < natures.getLength(); i++) {
65 |             if (WTP_NATURE.equals(natures.item(i).getTextContent().trim())) {
66 |                 webProject = true;
67 |                 break;
68 |             }
69 |         }
70 | 
71 |         // ── .classpath ────────────────────────────────────────────
72 |         Path classpathFile = inputDir.resolve(".classpath");
73 |         Document cpDoc = builder.parse(classpathFile.toFile());
74 |         cpDoc.getDocumentElement().normalize();
75 | 
76 |         List<String> sourceFolders = new ArrayList<>();
77 |         List<String> jarPaths = new ArrayList<>();
78 |         String outputFolder = null;
79 | 
80 |         NodeList entries = cpDoc.getElementsByTagName("classpathentry");
81 |         for (int i = 0; i < entries.getLength(); i++) {
82 |             Element entry = (Element) entries.item(i);
83 |             String kind = entry.getAttribute("kind");
84 |             String path = entry.getAttribute("path");
85 | 
86 |             switch (kind) {
87 |                 case "src" -> {
88 |                     if (!isOptional(entry)) {
89 |                         sourceFolders.add(path);
90 |                     }
91 |                 }
92 |                 case "output" -> outputFolder = path;
93 |                 case "lib" -> jarPaths.add(path);
94 |                 case "con" -> {
95 |                 }
96 |             }
97 |         }
98 | 
99 |         // ── .settings/org.eclipse.jdt.core.prefs ─────────────────
100 |         // source/target を prefs から取得し、見つからない場合は .classpath の con エントリの値を使う
101 |         String[] versions = parseJdtCorePrefs(inputDir);
102 |         JavaVersion javaSourceVersion = JavaVersion.of(versions[0]);
103 |         JavaVersion javaTargetVersion = JavaVersion.of(versions[1]);
104 | 
105 |         // ── WTP: .settings/org.eclipse.wst.common.component ──────
106 |         String webContentRoot = null;
107 |         String webVersion = null;
108 |         if (webProject) {
109 |             webContentRoot = parseWebContentRoot(inputDir, builder);
110 |             webVersion = parseWebVersion(inputDir, builder);
111 |             if (webContentRoot != null) {
112 |                 Path webInfLib = inputDir.resolve(webContentRoot).resolve("WEB-INF/lib");
113 |                 if (Files.isDirectory(webInfLib)) {
114 |                     jarPaths.add(webContentRoot + "/WEB-INF/lib");
115 |                 }
116 |             }
117 |         }
118 | 
119 |         return new EclipseProject(
120 |                 projectName,
121 |                 webProject,
122 |                 List.copyOf(sourceFolders),
123 |                 outputFolder,
124 |                 List.copyOf(jarPaths),
125 |                 webContentRoot,
126 |                 javaSourceVersion,
127 |                 javaTargetVersion,
128 |                 webVersion
129 |         );
130 |     }
131 | 
132 |     /**
133 |      * `.settings/org.eclipse.jdt.core.prefs` を解析して [sourceVersion, targetVersion] を返す。
134 |      * ファイルが存在しない、またはキーが見つからない場合は fallback 値を使用する。
135 |      */
136 |     private static String[] parseJdtCorePrefs(Path inputDir) {
137 |         Path prefsFile = inputDir.resolve(".settings")
138 |                 .resolve("org.eclipse.jdt.core.prefs");
139 | 
140 |         if (Files.exists(prefsFile)) {
141 |             Properties props = new Properties();
142 |             try (var reader = Files.newBufferedReader(prefsFile)) {
143 |                 props.load(reader);
144 |                 String source = normalizeJavaVersion(
145 |                         props.getProperty("org.eclipse.jdt.core.compiler.source"));
146 |                 String target = normalizeJavaVersion(
147 |                         props.getProperty("org.eclipse.jdt.core.compiler.codegen.targetPlatform"));
148 |                 // 両方取得できた場合はそのまま使う。片方のみの場合はもう一方も同じ値にする
149 |                 if (source != null && target != null) {
150 |                     return new String[]{source, target};
151 |                 } else if (source != null) {
152 |                     return new String[]{source, source};
153 |                 } else if (target != null) {
154 |                     return new String[]{target, target};
155 |                 }
156 |             } catch (IOException e) {
157 |                 // 読み込み失敗時は fallback を使用
158 |             }
159 |         }
160 | 
161 |         return new String[]{DEFAULT_JAVA_VERSION, DEFAULT_JAVA_VERSION};
162 |     }
163 | 
164 |     /**
165 |      * "1.8" → "1.8"、"17" → "17" のようにそのまま返す。
166 |      * null や空文字の場合は null を返す。
167 |      */
168 |     private static String normalizeJavaVersion(String value) {
169 |         if (value == null || value.isBlank()) {
170 |             return null;
171 |         }
172 |         return value.trim();
173 |     }
174 | 
175 |     /**
176 |      * `.settings/org.eclipse.wst.common.component` を解析して Webコンテンツルートを返す。
177 |      * ファイルが存在しない場合は null を返す。
178 |      * 先頭の "/" は除去した相対パスとして返す。
179 |      */
180 |     private static String parseWebContentRoot(Path inputDir, DocumentBuilder builder) {
181 |         Path componentFile = inputDir.resolve(".settings")
182 |                 .resolve("org.eclipse.wst.common.component");
183 | 
184 |         if (!Files.exists(componentFile)) {
185 |             return null;
186 |         }
187 | 
188 |         try {
189 |             Document doc = builder.parse(componentFile.toFile());
190 |             doc.getDocumentElement().normalize();
191 | 
192 |             NodeList resources = doc.getElementsByTagName("wb-resource");
193 |             for (int i = 0; i < resources.getLength(); i++) {
194 |                 Element res = (Element) resources.item(i);
195 |                 if ("defaultRootSource".equals(res.getAttribute("tag"))) {
196 |                     String sourcePath = res.getAttribute("source-path");
197 |                     // 先頭の "/" を除去して相対パスに正規化
198 |                     if (sourcePath.startsWith("/")) {
199 |                         sourcePath = sourcePath.substring(1);
200 |                     }
201 |                     return sourcePath;
202 |                 }
203 |             }
204 |         } catch (Exception e) {
205 |             // ファイルが壊れている場合は null を返す
206 |         }
207 | 
208 |         return null;
209 |     }
210 | 
211 |     /**
212 |      * {@code classpathentry} 要素が optional かどうかを返す。
213 |      * {@code <attributes>} 子要素内に {@code <attribute name="optional" value="true"/>} が
214 |      * 存在する場合に {@code true} を返す。
215 |      */
216 |     private static boolean isOptional(Element entry) {
217 |         NodeList attributesList = entry.getElementsByTagName("attributes");
218 |         if (attributesList.getLength() == 0) {
219 |             return false;
220 |         }
221 |         NodeList attributes = ((Element) attributesList.item(0)).getElementsByTagName("attribute");
222 |         for (int i = 0; i < attributes.getLength(); i++) {
223 |             Element attr = (Element) attributes.item(i);
224 |             if ("optional".equals(attr.getAttribute("name"))
225 |                     && "true".equals(attr.getAttribute("value"))) {
226 |                 return true;
227 |             }
228 |         }
229 |         return false;
230 |     }
231 | 
232 |     /**
233 |      * `.settings/org.eclipse.wst.common.project.facet.core.xml` を解析して
234 |      * {@code jst.web} ファセットの version を返す。
235 |      * ファイルが存在しない、またはファセットが見つからない場合は null を返す。
236 |      */
237 |     private static String parseWebVersion(Path inputDir, DocumentBuilder builder) {
238 |         Path facetFile = inputDir.resolve(".settings")
239 |                 .resolve("org.eclipse.wst.common.project.facet.core.xml");
240 | 
241 |         if (!Files.exists(facetFile)) {
242 |             return null;
243 |         }
244 | 
245 |         try {
246 |             Document doc = builder.parse(facetFile.toFile());
247 |             doc.getDocumentElement().normalize();
248 | 
249 |             NodeList installed = doc.getElementsByTagName("installed");
250 |             for (int i = 0; i < installed.getLength(); i++) {
251 |                 Element el = (Element) installed.item(i);
252 |                 if ("jst.web".equals(el.getAttribute("facet"))) {
253 |                     return el.getAttribute("version");
254 |                 }
255 |             }
256 |         } catch (Exception e) {
257 |             // ファイルが壊れている場合は null を返す
258 |         }
259 | 
260 |         return null;
261 |     }
262 | }
